update article
title = #{article.title}, summary = #{article.summary}, content = #{article.content}, cover_url = #{article.coverUrl}, category_id = #{article.categoryId}, status = #{article.status}, audit_status = #{article.auditStatus}, is_top = #{article.isTop}, update_by = #{article.updateBy}, update_time = #{article.updateTime}
