mapper.select:
select a.id, a.title, a.category_id, c.name as category_name, a.summary, a.cover_url as cover_image, a.status, a.audit_status, a.is_top, a.create_time from article a left join category c on a.category_id = c.id and c.is_deleted = 0 where a.is_deleted = 0 and a.create_by = #{currentUserId}
and a.title like concat('%', #{queryDTO.title}, '%')
and a.category_id = #{queryDTO.categoryId}
and a.status = #{queryDTO.status}
and a.audit_status = #{queryDTO.auditStatus}
order by a.id desc
